import{_ as t,o,c as s,a2 as d}from"./chunks/framework.DvFsUg-r.js";const u=JSON.parse('{"title":"관리자 콘솔 프론트엔드를 기준 디자인(lego)과 동일하게 맞추기","description":"","frontmatter":{"slug":"lego-design-port","title":"관리자 콘솔 프론트엔드를 기준 디자인(lego)과 동일하게 맞추기","authors":[],"tags":["frontend","vue","vuetify","design-system","admin-console","feature-006","refactor"],"created":"2026-06-07 12:15 (KST)","date":"2026-06-07T03:15:00.000Z"},"headers":[],"relativePath":"journal/2026-06-07-lego-design-port.md","filePath":"journal/2026-06-07-lego-design-port.md","lastUpdated":1781092690000}'),a={name:"journal/2026-06-07-lego-design-port.md"};function i(r,e,n,l,c,g){return o(),s("div",null,[...e[0]||(e[0]=[d(`<p>feature 006 으로 가져온 관리자 콘솔(<code>app/src/main/frontend</code>)의 사용자·메뉴 관리와 메인 화면이 <strong>디자인·UI/UX 가 기준과 전혀 달라</strong> 엉망이었다. 기준은 spec 006 plan 에 명시된 이전 소스 <code>C:/ax/lego</code>(Vue3 · Vuetify · Pinia). 모든 화면을 lego 와 시각적으로 동일하게 맞췄다.</p><h2 id="진단-—-엉망-의-근본-원인은-테마-한-줄이었다" tabindex="-1">진단 — &quot;엉망&quot;의 근본 원인은 테마 한 줄이었다 <a class="header-anchor" href="#진단-—-엉망-의-근본-원인은-테마-한-줄이었다" aria-label="Permalink to &quot;진단 — &quot;엉망&quot;의 근본 원인은 테마 한 줄이었다&quot;">​</a></h2><p>화면 코드(부서·사용자 뷰)는 멀쩡한 Vuetify 였는데 전체가 기본 파란색·각진 모서리로 나왔다. 원인은 부트스트랩에 있었다:</p><div class="language-ts vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">ts</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">// main.ts — 옵션 없이 호출 → Vuetify 기본 테마 그대로</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">const</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> vuetify</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> =</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> createVuetify</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">()</span></span></code></pre></div><p>lego 는 <code>plugins/vuetify.ts</code> 에 <strong>Indigo(#6366F1) 라이트/다크 테마 + 컴포넌트 기본값</strong>(둥근 버튼·xl 카드·outlined compact 입력)을, <code>assets/global.scss</code> 에 <strong>카드 글래스·데이터테이블·앱바·버튼·칩 룩</strong>을 전역으로 깔아둔다. 이 토대가 통째로 빠져 있었다. 이 둘만 이식해도 전체 분위기의 70%가 lego 로 바뀐다.</p><h2 id="원칙-—-시각은-복제-백엔드-의존은-끊는다" tabindex="-1">원칙 — 시각은 복제, 백엔드 의존은 끊는다 <a class="header-anchor" href="#원칙-—-시각은-복제-백엔드-의존은-끊는다" aria-label="Permalink to &quot;원칙 — 시각은 복제, 백엔드 의존은 끊는다&quot;">​</a></h2><p>lego 화면을 그대로 베끼면 lego 전용 플러그인까지 끌려온다. 화면은 동일하게 두되 의존은 현재 앱의 기존 <code>api/</code>·<code>stores/</code> 로 갈아끼웠다.</p><table tabindex="0"><thead><tr><th>lego 의존</th><th>현재 앱 대체</th></tr></thead><tbody><tr><td><code>$msg</code> (i18n)</td><td>한국어 리터럴 (i18n 은 후속)</td></tr><tr><td><code>$lego.getCodeName</code> (코드그룹)</td><td>화면 내 상태 옵션 + 칩 색상</td></tr><tr><td><code>CodeSelect</code></td><td>정적 <code>v-select</code></td></tr><tr><td><code>useSearchFilter</code> (서버 저장 프리셋)</td><td>동일 외형 필터 — <strong>저장만 생략</strong></td></tr><tr><td>echarts · dashboard API</td><td>stat-card + 기존 목록 API 카운트</td></tr></tbody></table><h2 id="한-일-커밋-8개" tabindex="-1">한 일 (커밋 8개) <a class="header-anchor" href="#한-일-커밋-8개" aria-label="Permalink to &quot;한 일 (커밋 8개)&quot;">​</a></h2><ul><li><strong>토대</strong> — <code>vuetify.ts</code>(테마·기본값) + <code>global.css</code>(전역 룩) 이식, <code>main.ts</code> 교체. 순수 CSS 문법이라 <code>sass</code> 의존 없이 <code>.css</code> 로 작성.</li><li><strong>앱 셸</strong> — 글래스 앱바 · 그라데이션 로고 · 유저 드롭다운(프로필 · <strong>다크모드 토글</strong> · 로그아웃) · 페이지 타이틀 · 재귀 <code>SidebarMenuItem</code>(활성 강조 · 들여쓰기 · 펼침 애니메이션). lego <code>Menu</code> 타입 대신 현재 <code>MenuNode</code>(<code>menuId</code>)에 맞춰 적응.</li><li><strong>로그인</strong> — 애니메이션 배경 · 글래스 카드 · 비밀번호 토글. <code>authStore.login(객체)</code> → 현재의 <code>login(username, password)</code> 2-인자 시그니처로 적응.</li><li><strong>목록 화면</strong>(사용자·역할·부서·메뉴) — 검색 + &quot;전체 N건&quot; 바 · outlined 카드 래핑 · 상태/역할 <strong>칩</strong> · 빈상태 · 폼 검증.</li><li><strong>대시보드</strong> — echarts 없이 lego stat-card 외형 + 기존 목록 API 의 <code>totalElements</code> 로 카운트(관리자만, 403 은 0).</li><li><strong>프로필</strong> — 검증 폼 + 카드 구조(이름·이메일·언어 / 비밀번호 변경 / 즐겨찾기).</li></ul><h2 id="막혔던-지점" tabindex="-1">막혔던 지점 <a class="header-anchor" href="#막혔던-지점" aria-label="Permalink to &quot;막혔던 지점&quot;">​</a></h2><ul><li><strong>빌드 산출물 커밋 여부</strong> — <code>static/app</code> 이 git 에 untracked 라 헷갈렸는데, 프론트 <code>.gitignore</code> 주석에 &quot;빌드 시 생성, 커밋 제외&quot;가 명시돼 있었다(Gradle node 플러그인이 <code>vite build</code> 수행). 산출물은 커밋하지 않는 게 관례.</li><li><strong>DataGrid 하위 호환</strong> — 공통 그리드를 lego 패턴으로 보강하되, 기존 뷰가 의존하는 <code>#actions</code>·<code>#item.*</code> 슬롯과 <code>@update:query</code> 계약을 그대로 보존해야 했다.</li></ul><h2 id="결과" tabindex="-1">결과 <a class="header-anchor" href="#결과" aria-label="Permalink to &quot;결과&quot;">​</a></h2><ul><li><code>vue-tsc --noEmit &amp;&amp; vite build</code> <strong>통과</strong>, 단위테스트 <strong>13/13</strong> 통과.</li><li>모든 화면이 lego 의 Indigo·글래스·칩·라운드 디자인으로 통일.</li><li>다만 <strong>브라우저 픽셀 비교는 미실시</strong>(로그인에 백엔드 구동 필요) — <code>npm run dev</code> 로 눈 확인 권장.</li></ul><p>설계·계획은 <code>docs/superpowers/specs/2026-06-07-lego-design-port-design.md</code> 와 <code>docs/superpowers/plans/2026-06-07-lego-design-port.md</code> 에 남겼다. 기준 출처 규약은 <code>specs/006-platform-admin-frontend/</code>.</p>`,15)])])}const h=t(a,[["render",i]]);export{u as __pageData,h as default};
